INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b67ca510-5ae6-4bbf-9226-c0bfaf968c36',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun's Concurrency Model — One Thread, Many Promises, Zero Goroutines$escape$,
  $escape$Bun runs on JavaScriptCore's single-threaded event loop — no goroutines, no actor model, no shared-memory threads by default. Concurrency is cooperative: async/await suspends execution at every `await`, yielding control back to the event loop so other microtasks can proceed. Bun uses JavaScriptCore's JIT-compiled promise machinery, which is measurably faster than V8's for tight async workloads.

For true parallelism, Bun exposes the Web Workers API (`new Worker()`). Each worker runs in its own JSC isolate with its own event loop — no shared heap, communication only via `postMessage` and `SharedArrayBuffer` with `Atomics`. Bun.spawn() and Bun.spawnSync() offload work to child processes, not threads.

Bun's I/O (fetch, Bun.file, Bun.serve) is non-blocking under the hood via libuv/io_uring on Linux, so saturating the event loop with CPU work — not I/O — is the actual bottleneck. For CPU-heavy tasks, reach for Worker threads or Bun.spawn, not more awaits.$escape$,
  $escape$// CPU-bound work offloaded to a Bun Worker
// worker.ts
self.onmessage = (e) => {
  const result = heavyCompute(e.data);
  self.postMessage(result);
};

// main.ts
const worker = new Worker(new URL("./worker.ts", import.meta.url));
worker.postMessage({ input: [1, 2, 3] });
worker.onmessage = (e) => console.log("Result:", e.data);

// Non-blocking I/O — no worker needed, event loop handles it
const [a, b] = await Promise.all([
  fetch("https://api.example.com/a").then(r => r.json()),
  Bun.file("./data.json").json(),
]);$escape$,
