INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '833be01f-d56e-4bbf-9d65-1aaf6d84b5e3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun's TypeScript-First Runtime — Type Safety Without the Build Step$escape$,
  $escape$Bun executes TypeScript natively — no tsc, no ts-node, no transpile step. This means you get full static typing at authoring time while Bun strips types at runtime via its built-in transpiler (based on JavaScriptCore). The implication: type errors are caught in your editor and CI, not at runtime, but Bun itself never enforces them during execution. Use `bun --smol` or `bun typecheck` (wraps tsc with your tsconfig) to run a pure type-check pass without emitting files. Generics work as expected since they're erased pre-execution. Where Bun shines is inference-heavy APIs: `Bun.file()` returns a typed `BunFile`, `Bun.serve()` infers request/response shapes from your handler signature, and `$` from `bun:shell` is fully typed. For strict projects, pair `"strict": true` in tsconfig with `bun typecheck` in CI. You get the ergonomics of a dynamic runtime with the guarantees of a statically typed language — the key is understanding that the safety net is the toolchain, not the runtime.$escape$,
  $escape$// bun typecheck catches this before execution — no build step needed
import { serve } from "bun";

type Handler = (req: Request) => Response | Promise<Response>;

const json = <T>(data: T, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });

const handler: Handler = async (req) => {
  const body = await req.json<{ name: string }>();
  return json({ hello: body.name.toUpperCase() }); // type-safe: name is string
};

serve({ port: 3000, fetch: handler });$escape$,
  $escape$typescript$escape$,
