INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '25886f36-148f-435a-9e01-d26d3bedd268',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun Error Handling — throw/catch vs Result Types and Where Each Belongs$escape$,
  $escape$Bun's runtime is pure throw/catch — no built-in Result type. But TypeScript lets you layer typed Results on top, and the distinction matters at scale. Thrown errors erase type information at call sites; a `Result<T, E>` union forces callers to handle failure explicitly.

Bun's I/O APIs (`Bun.file()`, `fetch()`, `Bun.connect()`) all throw on failure — treat these as the boundary. Wrap them in thin adapters that return `{ ok: true, data }` or `{ ok: false, error }` unions, keeping thrown errors confined to the edges. Inside your domain logic, propagate Results; never let a raw throw leak across a feature boundary.

In `Bun.serve()`, the `error` hook is your last-resort catch-all for unhandled throws escaping route handlers — log and return a 500 there, but don't rely on it for expected failure paths. For route handlers, typed Results are superior: a `Promise<Result<User, AuthError>>` return type is self-documenting and exhaustively checked by TypeScript. Use `neverthrow` or a simple two-line union — Bun's fast startup means the overhead is negligible.$escape$,
  $escape$import { Bun } from 'bun';

type Result<T, E> = { ok: true; data: T } | { ok: false; error: E };

async function readConfig(path: string): Promise<Result<string, Error>> {
  try {
    const text = await Bun.file(path).text();
    return { ok: true, data: text };
  } catch (e) {
    return { ok: false, error: e as Error };
  }
}

Bun.serve({
  async fetch(req) {
    const result = await readConfig('./config.json');
    if (!result.ok) return new Response('Config missing', { status: 500 });
    return new Response(result.data);
  },
  error(err) {
    console.error('[unhandled]', err);
    return new Response('Internal error', { status: 500 });
  },
});$escape$,
  $escape$typescript$escape$,
