INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1dea5f5f-feed-493b-90fa-b4fa3ae5b7b2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun's Built-In Benchmarking — Profiling Runtime Performance Without External Tools$escape$,
  $escape$Bun ships a native `Bun.bench()` API that eliminates the need for tools like `benchmark.js` or `tinybench`. It integrates directly with the JavaScriptCore engine, meaning measurements reflect true JIT-warmed execution rather than cold V8 estimates.

Run benchmarks with `bun bench ./perf.bench.ts` — Bun auto-discovers files matching `*.bench.{ts,js}`. Each `bench()` call runs thousands of iterations, reports ops/sec, and flags statistical outliers. Use `group()` to compare variants side-by-side under the same warmup conditions.

For CPU profiling, `bun --smol run script.ts` reduces heap size to surface memory-pressure bottlenecks. Pair with `bun --inspect` to attach the WebKit Inspector and capture flame graphs natively — no `--prof` V8 flags or `0x` post-processing needed.

Bun's HTTP server (`Bun.serve`) consistently benchmarks 3–4× faster than Node's `http` module in published results, largely due to uWebSockets under the hood. Profile your hot paths with `bench()` before assuming the bottleneck is I/O — JSC's optimizer can surprise you.$escape$,
  $escape$import { bench, group, run } from "bun:test";

const data = Array.from({ length: 1000 }, (_, i) => i);

group("array iteration", () => {
  bench("for loop", () => {
    let sum = 0;
    for (let i = 0; i < data.length; i++) sum += data[i];
  });

  bench("reduce", () => {
    data.reduce((acc, val) => acc + val, 0);
  });

  bench("for...of", () => {
    let sum = 0;
    for (const val of data) sum += val;
  });
});

await run();$escape$,
  $escape$typescript$escape$,
