INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6de6da0d-690c-4a4d-b079-b78c16934c90',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun Memory Management — JSC GC, Stack Pressure, and Zero-Copy Wins$escape$,
  $escape$Bun runs on JavaScriptCore (JSC), not V8 — a meaningful difference for memory. JSC uses a generational, semi-space copying collector with a separate large object heap. Small objects get bumped into eden space; survivors are promoted. This means short-lived allocations are cheap, but large object churn (>32KB) hits the large heap and triggers slower full GCs.

Bun exposes `Bun.gc(true)` for synchronous collection — useful in benchmarks to baseline heap state. For heap inspection, `process.memoryUsage()` returns rss, heapUsed, and heapTotal consistent with Node's contract.

The real win is zero-copy I/O. `Bun.file()` returns a lazy `BunFile` — no bytes are read until you call `.text()`, `.json()`, or `.arrayBuffer()`. Piping via `Response` skips userspace entirely. For hot paths, prefer `TypedArray` slices over string concatenation — they live in the ArrayBuffer heap with predictable GC pressure. Avoid closing over large objects in long-lived callbacks; JSC's escape analysis won't help you if the closure root is reachable.$escape$,
  $escape$// Observe heap before and after a GC cycle in Bun
const before = process.memoryUsage();

// Allocate some short-lived objects
const blobs = Array.from({ length: 10_000 }, (_, i) => ({ id: i, data: new Uint8Array(64) }));
void blobs;

// Force synchronous GC (JSC) — useful in benchmarks, not production
Bun.gc(true);

const after = process.memoryUsage();
console.log("heapUsed delta (KB):", ((after.heapUsed - before.heapUsed) / 1024).toFixed(1));

// Zero-copy file read — no heap allocation until consumed
const file = Bun.file("./large-dataset.json");
const stream = file.stream(); // still lazy
const response = new Response(stream); // piped without userspace copy
await Bun.write(Bun.stdout, response);$escape$,
  $escape$typescript$escape$,
