INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c335fae1-b610-4a4d-902c-ba9fd931220d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun's JavaScriptCore Engine — Why Cold Starts Are Near Zero$escape$,
  $escape$Bun is built on JavaScriptCore (JSC), the same engine powering Safari — not V8. JSC uses a tiered JIT pipeline: LLInt (bytecode interpreter) → DFG (Data Flow Graph JIT) → FTL (Forth-Tier LLVM) JIT. On startup, Bun skips the slow baseline compilation step that Node.js/V8 performs, landing in LLInt immediately and letting JSC's JIT warm up mid-execution.

Beyond JSC, Bun's runtime itself is compiled to native code via Zig, eliminating Node's libuv + JS-layer bootstrap overhead. The result: Bun consistently starts in ~5–10ms vs Node's ~80–150ms on identical scripts.

Bun also ships with a bundler that can output a single-file executable via `bun build --compile`, embedding the JSC engine and your JS into a native binary. This pre-parses and bytecode-caches your entry point at build time — cold start in production drops to near-native speeds, with no JIT warmup penalty on first request.

For serverless and edge workloads, this matters: you get JIT-optimized throughput without sacrificing cold-start latency.$escape$,
  $escape$// Build a self-contained native binary — cold start ~5ms
// bun build --compile ./src/server.ts --outfile server

import { serve } from "bun";

serve({
  port: 3000,
  fetch(req) {
    return new Response("ok");
  },
});

// Measure Bun vs Node cold start yourself:
// time bun run server.ts
// time node server.js$escape$,
  $escape$typescript$escape$,
