INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '61e61072-43bd-40a5-ae89-c19206c58c0c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun's Built-in Test Runner — Zero Config, Full Speed$escape$,
  $escape$Bun ships a native test runner (`bun:test`) that requires no external dependencies — no Jest, no Vitest, no config files. It's Jest-compatible by design, so `describe`, `it`, `expect`, `beforeEach`, and `afterEach` all work out of the box. Run your suite with `bun test` and Bun automatically discovers files matching `*.test.ts`, `*.spec.ts`, or files inside `__tests__/`.

Bun's test runner executes in the same runtime as your app code, so there's no transpilation step and no module resolution mismatch — what you import in tests is exactly what ships. This eliminates an entire class of "passes in test, fails in prod" bugs.

For mocking, use `mock()` from `bun:test` instead of `jest.fn()`. It supports spies, module mocks via `mock.module()`, and restore with `mock.restore()`. Snapshot testing works via `expect(value).toMatchSnapshot()` with snapshots stored in `__snapshots__/`.

Unit test philosophy in Bun: keep tests co-located with source, lean on TypeScript types to narrow test surface, and use `--watch` mode during development for sub-10ms feedback loops.$escape$,
  $escape$import { describe, it, expect, mock, beforeEach } from "bun:test";
import { fetchUser } from "./user-service";

const mockFetch = mock(() =>
  Promise.resolve({ json: () => ({ id: 1, name: "Alice" }) })
);

beforeEach(() => mockFetch.mockClear());

describe("fetchUser", () => {
  it("returns parsed user from response", async () => {
    globalThis.fetch = mockFetch as typeof fetch;
    const user = await fetchUser(1);
    expect(user).toEqual({ id: 1, name: "Alice" });
    expect(mockFetch).toHaveBeenCalledTimes(1);
  });
});$escape$,
