INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c8c6bba9-dcf7-41d4-b3dd-d67fd7c6634a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun's Built-In Linter and Formatter — Zero Config, Zero Overhead$escape$,
  $escape$Bun ships with `bun lint` and `bun fmt` natively — no ESLint config files, no Prettier dependencies, no `node_modules` bloat. Both commands are backed by Bun's Rust-based toolchain, making them 10–100x faster than Node-era equivalents.

`bun lint` runs a strict, opinionated ruleset by default — catching unused variables, implicit `any` in TypeScript, and unreachable code. Rules are configured via `bunfig.toml` under `[lint]`, not a separate `.eslintrc`. You can suppress individual rules inline with `// bun-ignore` comments.

`bun fmt` enforces consistent style using the same formatter as Biome under the hood — 2-space indentation, double quotes, trailing commas in multiline. Override defaults in `bunfig.toml` under `[fmt]`.

For CI enforcement, run both with `--check` flags: they exit non-zero on violations without mutating files. Pair with `bun test --coverage` in the same pipeline for a lean, dependency-free quality gate built entirely on Bun's own toolchain.$escape$,
  $escape$# bunfig.toml — centralized lint + fmt config
[lint]
rules = { noUnusedVariables = "error", noExplicitAny = "warn" }

[fmt]
indentWidth = 2
singleQuote = false
trailingComma = "all"

# CI quality gate — no extra deps needed
$ bun lint --check
$ bun fmt --check
$ bun test --coverage$escape$,
  $escape$bash$escape$,
