INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '190a118a-c168-4312-a4dc-2991dda91448',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun — Ship Tiny Containers with bun build --compile$escape$,
  $escape$Bun's `--compile` flag bundles your entire app — source, dependencies, and the Bun runtime — into a single self-contained binary. No node_modules, no runtime installation, no package.json required at deploy time. The resulting binary typically lands between 50–90 MB depending on your code, because the Bun runtime itself is embedded. For containerization, this changes the game: you can use a `FROM scratch` or `FROM gcr.io/distroless/static` base image instead of a Node/Bun runtime image (which can exceed 400 MB). Cross-compile for Linux from macOS with `--target bun-linux-x64` or `--target bun-linux-arm64` before your Docker build step. The binary has zero runtime dependencies — no libc calls to worry about with the static target. For secrets and env vars, Bun still reads `process.env` at runtime, so your existing injection patterns work unchanged. Use `bun build --compile --minify --sourcemap=none ./src/index.ts --outfile server` in CI, then `COPY server /server` in your Dockerfile for a sub-100 MB production image.$escape$,
  $escape$# Build a self-contained Linux binary from macOS/Windows CI
bun build ./src/index.ts \
  --compile \
  --minify \
  --target bun-linux-x64-baseline \
  --outfile server

# Minimal Dockerfile — no Bun or Node runtime needed
FROM gcr.io/distroless/static-debian12
COPY --chown=nonroot:nonroot server /server
USER nonroot
EXPOSE 3000
ENTRYPOINT ["/server"]$escape$,
  $escape$bash$escape$,
