INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c19431ed-59ff-4973-a071-bb406d4123df',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun's Event Loop — Why It Feels Faster Than Node.js$escape$,
  $escape$Bun runs on JavaScriptCore (JSC) and uses a single-threaded event loop backed by uSockets — the same C library powering uWebSockets.js. Unlike Node.js (libuv), Bun's I/O layer is tightly integrated with JSC's microtask queue, meaning promise continuations and I/O callbacks are scheduled with less overhead.

In practice: `Bun.serve()` handles HTTP via native uSockets bindings, bypassing the Node.js stream abstraction entirely. Timers use JSC's built-in scheduler rather than libuv's timer wheel, which reduces timer jitter at high concurrency.

CPU-bound work still blocks the event loop. Use `new Worker()` (Bun's Web Worker implementation, backed by real OS threads) to offload heavy computation. Data is transferred via `postMessage` with structured clone — Bun also supports `SharedArrayBuffer` + `Atomics` for zero-copy shared memory between workers.

For async I/O, lean on `Bun.file()`, `fetch()`, and `Bun.connect()` — all implemented natively in Zig, not JS wrappers — so you stay on the fast path without leaving the event loop.$escape$,
  $escape$// CPU-bound work offloaded to a Bun Worker
const worker = new Worker(new URL('./heavy.ts', import.meta.url).href);

worker.postMessage({ data: largeBuffer }, [largeBuffer.buffer]);

worker.onmessage = (e) => {
  console.log('Result from worker thread:', e.data.result);
};

// heavy.ts
self.onmessage = (e) => {
  const result = computeExpensiveThing(e.data.data);
  self.postMessage({ result });
};$escape$,
  $escape$typescript$escape$,
