INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0f05ea68-a11d-4c2a-b957-d857d89553d5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun Security — Shell Injection, SQL Safety, and bun audit$escape$,
  $escape$Bun exposes three common attack surfaces that require explicit hardening. First, `Bun.spawn()` accepts both a string and an array — always use the array form. The string form is passed to a shell, making it trivially injectable; the array form bypasses the shell entirely, treating each element as a literal argument. Second, Bun's native postgres driver (`Bun.sql`) uses tagged template literals that automatically parameterize interpolated values — no manual escaping, no risk of SQLi. For SQLite, `bun:sqlite` prepared statements with `?` placeholders provide the same guarantee. Third, run `bun audit` to scan your lockfile against the GitHub Advisory Database for known CVEs. Unlike `npm audit`, it reads `bun.lockb` directly and skips network overhead from resolving the full dependency tree. Pair this with `bun audit --level high` in CI to fail builds on high-severity findings. None of these are Bun-specific concepts, but Bun's APIs make the safe path the ergonomic default — the template literal driver and array-spawn make it hard to do the wrong thing accidentally.$escape$,
  $escape$// UNSAFE — string form invokes a shell; userInput can escape
// Bun.spawn(`cat ${userInput}`);

// SAFE — array form: no shell, each arg is literal
Bun.spawn(["cat", userInput]);

// SQL injection prevention via tagged template (Bun.sql)
const rows = await Bun.sql`
  SELECT * FROM posts WHERE author_id = ${authorId} LIMIT 20
`;

// SQLite prepared statement — same guarantee
const db = new Database("app.db");
const stmt = db.prepare("SELECT * FROM posts WHERE author_id = ? LIMIT 20");
const posts = stmt.all(authorId);

// Audit lockfile for CVEs — run in CI
// bun audit --level high$escape$,
  $escape$typescript$escape$,
