INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7aacc18a-a611-4ea4-a74b-e72aca388d9a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun Runtime Metrics — Profiling and Monitoring in Production$escape$,
  $escape$Bun exposes runtime internals through `Bun.gc()`, `process.memoryUsage()`, and the built-in `--smol` flag for memory-constrained environments. Unlike Node, Bun uses JavaScriptCore (JSC), which has a generational GC with distinct Eden and full heap collections — understanding this distinction matters for latency-sensitive services.

Track GC pressure by sampling `heapUsed` over time. A rising `heapUsed` with periodic drops signals full GC cycles; sustained growth without drops indicates a leak. Call `Bun.gc(true)` to force a synchronous collection — useful in health check endpoints to baseline actual retained heap.

For CPU profiling, Bun supports the V8 inspector protocol via `--inspect`. Attach Chrome DevTools or use `bun --inspect-brk` to capture flame graphs. In production, wrap hot paths with `performance.mark()` and `performance.measure()` — both are natively supported with microsecond resolution in Bun's JSC runtime, no polyfill needed.

Expose a `/metrics` endpoint that streams these snapshots to Prometheus via a simple interval loop — no native Bun metrics SDK is required.$escape$,
  $escape$import { serve } from "bun";

function getRuntimeMetrics() {
  const mem = process.memoryUsage();
  Bun.gc(false); // async hint to JSC GC
  return {
    heapUsedMB: (mem.heapUsed / 1024 / 1024).toFixed(2),
    heapTotalMB: (mem.heapTotal / 1024 / 1024).toFixed(2),
    externalMB: (mem.external / 1024 / 1024).toFixed(2),
    rss: (mem.rss / 1024 / 1024).toFixed(2),
  };
}

serve({
  port: 9091,
  fetch(req) {
    if (new URL(req.url).pathname === "/metrics") {
      const m = getRuntimeMetrics();
      const body = Object.entries(m)
        .map(([k, v]) => `bun_${k} ${v}`)
        .join("\n");
      return new Response(body, { headers: { "Content-Type": "text/plain" } });
    }
    return new Response("not found", { status: 404 });
  },
});$escape$,
  $escape$typescript$escape$,
