INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e024dd9f-1981-479d-b2e1-121bc2b683ab',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun Horizontal Scaling — reusePort, Workers, and the Share-Nothing Thread Model$escape$,
  $escape$Bun's HTTP server runs one event loop per process on JavaScriptCore — same single-threaded model as Node, but with lower memory overhead and faster cold start. The key primitive for horizontal scaling is `reusePort: true` in `Bun.serve()`. This sets SO_REUSEPORT on the socket, letting multiple Bun processes bind to the same port simultaneously. The OS kernel distributes incoming connections across them — no cluster module, no primary/worker IPC overhead, no round-robin coordination in userspace.

To saturate all cores, spawn one Bun process per CPU and let the kernel load-balance. For CPU-bound work inside a process, `new Worker('./worker.ts')` creates a separate thread with its own JSC heap — communicate via `postMessage` with structured clone or transferable ArrayBuffers for zero-copy.

The critical implication: Bun's model is share-nothing. In-memory state (caches, counters, connection pools) is isolated per process. Design handlers to be stateless, push shared state to Redis or Postgres, and instantiate DB clients per-process — a single `Database` from `bun:sqlite` opened globally is not shared across `reusePort` siblings. Horizontal scaling in Bun rewards pure function handlers and external state stores.$escape$,
  $escape$// server.ts — run one process per core, all bound to :3000
import { cpus } from "os";

if (!process.env.IS_WORKER) {
  for (let i = 0; i < cpus().length; i++) {
    Bun.spawn(["bun", "run", "server.ts"], {
      env: { ...process.env, IS_WORKER: "1" },
      stdout: "inherit",
    });
  }
} else {
  Bun.serve({
    port: 3000,
    reusePort: true,
    fetch(req) {
      return new Response(`pid ${process.pid}`);
    },
  });
}$escape$,
