INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '385f0a64-f3c7-4417-b0b0-1c5c5b30c63b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bun Ecosystem Maturity — Built-ins That Kill npm Dependencies and Where Native Gaps Still Bite$escape$,
  $escape$Bun targets full Node.js API compatibility, meaning most of npm's 2M+ packages run unmodified. The real gap: packages shipping precompiled `.node` bindings—`bcrypt`, older `sharp`, `canvas`—fail silently or hard. The fix is usually a WASM drop-in: swap `bcrypt` for `@node-rs/bcrypt`, use `sharp` v0.33+ which ships its own WASM path.

Bun's first-party modules eliminate entire dependency categories. `bun:sqlite` replaces `better-sqlite3` with near-identical API. `Bun.file()` and `Bun.write()` replace `fs-extra`. `bun:ffi` handles native calls without `node-ffi-napi`. The `bun:test` runner mirrors Jest's API—most `.test.ts` files migrate with zero edits.

Oven.sh ships aggressively: Node.js compat PRs land weekly, v1.1 brought stable Windows support marking a real maturity inflection. The GitHub star count (~75K) lags Node's by an order of magnitude, but issues close fast and the Discord is high signal. For greenfield backends, Bun's coverage is production-ready. For legacy codebases with deep native deps, run `bun install` on a branch and watch for `WARN failed to resolve native addon` before committing.$escape$,
  $escape$// bun:sqlite — zero npm deps, replaces better-sqlite3
import { Database } from "bun:sqlite";

const db = new Database(":memory:");
db.run("CREATE TABLE events (id INTEGER PRIMARY KEY, name TEXT, ts INTEGER)");
db.run("INSERT INTO events (name, ts) VALUES (?, ?)", ["deploy", Date.now()]);

const recent = db.query("SELECT * FROM events WHERE ts > ?").all(Date.now() - 60_000);
console.log(recent);

// Bun.file replaces fs + JSON.parse boilerplate
const config = await Bun.file("bun.config.json").json<{ port: number }>();
console.log(`Starting on port ${config.port}`);$escape$,
  $escape$typescript$escape$,
